package allstar

import (
	"fmt"
	"strings"
)

// EmitGoSource returns Go source code for a function that constructs an
// equivalent RuntimeATN without calling CreateATN.  The generated function
// can be compiled into any package that imports the allstar package.
//
//	pkgName  – Go package name for the generated file (e.g. "myparser")
//	funcName – name of the generated constructor function
//	importPath – import path of the allstar package (e.g. "typefox.dev/fastbelt/parser/allstar")
func EmitGoSource(pkgName, funcName, importPath string, rtn *RuntimeATN) string {
	// Index each state pointer to its position in rtn.States.
	idx := make(map[*RuntimeATNState]int, len(rtn.States))
	for i, s := range rtn.States {
		idx[s] = i
	}

	var b strings.Builder
	fmt.Fprintf(&b, "// Code generated by fastbelt. DO NOT EDIT.\n\n")
	fmt.Fprintf(&b, "package %s\n\n", pkgName)
	fmt.Fprintf(&b, "import allstar %q\n\n", importPath)
	fmt.Fprintf(&b, "func %s() *allstar.RuntimeATN {\n", funcName)
	fmt.Fprintf(&b, "\tstates := make([]*allstar.RuntimeATNState, %d)\n", len(rtn.States))

	// Emit state declarations (without transitions so forward refs are fine).
	for i, s := range rtn.States {
		fmt.Fprintf(&b, "\tstates[%d] = &allstar.RuntimeATNState{\n", i)
		fmt.Fprintf(&b, "\t\tStateNumber: %d,\n", s.StateNumber)
		fmt.Fprintf(&b, "\t\tType: allstar.%s,\n", atnStateTypeName(s.Type))
		fmt.Fprintf(&b, "\t\tDecision: %d,\n", s.Decision)
		if s.EpsilonOnlyTransitions {
			fmt.Fprintf(&b, "\t\tEpsilonOnlyTransitions: true,\n")
		}
		if s.RuleName != "" {
			fmt.Fprintf(&b, "\t\tRuleName: %q,\n", s.RuleName)
		}
		if s.ProdIdx != 0 {
			fmt.Fprintf(&b, "\t\tProdKind: allstar.%s,\n", productionKindName(s.ProdKind))
			fmt.Fprintf(&b, "\t\tProdIdx: %d,\n", s.ProdIdx)
		}
		fmt.Fprintf(&b, "\t}\n")
	}

	// Emit transitions (states already declared, so pointer refs are valid).
	for i, s := range rtn.States {
		if len(s.Transitions) == 0 {
			continue
		}
		fmt.Fprintf(&b, "\tstates[%d].Transitions = []allstar.RuntimeTransition{\n", i)
		for _, t := range s.Transitions {
			switch at := t.(type) {
			case *RuntimeAtomTransition:
				fmt.Fprintf(&b, "\t\t&allstar.RuntimeAtomTransition{Target: states[%d], TokenTypeID: %d, CategoryMatches: %s},\n",
					idx[at.Target], at.TokenTypeID, emitIntSlice(at.CategoryMatches))
			case *RuntimeEpsilonTransition:
				fmt.Fprintf(&b, "\t\t&allstar.RuntimeEpsilonTransition{Target: states[%d]},\n", idx[at.Target])
			case *RuntimeRuleTransition:
				fmt.Fprintf(&b, "\t\t&allstar.RuntimeRuleTransition{Target: states[%d], FollowState: states[%d]},\n",
					idx[at.Target], idx[at.FollowState])
			}
		}
		fmt.Fprintf(&b, "\t}\n")
	}

	// DecisionStates slice.
	fmt.Fprintf(&b, "\tdecisionStates := make([]*allstar.RuntimeATNState, %d)\n", len(rtn.DecisionStates))
	for i, ds := range rtn.DecisionStates {
		if ds != nil {
			fmt.Fprintf(&b, "\tdecisionStates[%d] = states[%d]\n", i, idx[ds])
		}
	}

	// DecisionMap.
	fmt.Fprintf(&b, "\tdecisionMap := map[string]*allstar.RuntimeATNState{\n")
	for key, s := range rtn.DecisionMap {
		fmt.Fprintf(&b, "\t\t%q: states[%d],\n", key, idx[s])
	}
	fmt.Fprintf(&b, "\t}\n")

	fmt.Fprintf(&b, "\treturn &allstar.RuntimeATN{\n")
	fmt.Fprintf(&b, "\t\tStates:         states,\n")
	fmt.Fprintf(&b, "\t\tDecisionStates: decisionStates,\n")
	fmt.Fprintf(&b, "\t\tDecisionMap:    decisionMap,\n")
	fmt.Fprintf(&b, "\t}\n")
	fmt.Fprintf(&b, "}\n")
	return b.String()
}

func emitIntSlice(s []int) string {
	if len(s) == 0 {
		return "nil"
	}
	parts := make([]string, len(s))
	for i, v := range s {
		parts[i] = fmt.Sprintf("%d", v)
	}
	return "[]int{" + strings.Join(parts, ", ") + "}"
}

func atnStateTypeName(t ATNStateType) string {
	switch t {
	case ATNInvalidType:
		return "ATNInvalidType"
	case ATNBasic:
		return "ATNBasic"
	case ATNRuleStart:
		return "ATNRuleStart"
	case ATNPlusBlockStart:
		return "ATNPlusBlockStart"
	case ATNStarBlockStart:
		return "ATNStarBlockStart"
	case ATNTokenStart:
		return "ATNTokenStart"
	case ATNRuleStop:
		return "ATNRuleStop"
	case ATNBlockEnd:
		return "ATNBlockEnd"
	case ATNStarLoopBack:
		return "ATNStarLoopBack"
	case ATNStarLoopEntry:
		return "ATNStarLoopEntry"
	case ATNPlusLoopBack:
		return "ATNPlusLoopBack"
	case ATNLoopEnd:
		return "ATNLoopEnd"
	default:
		return fmt.Sprintf("ATNStateType(%d)", int(t))
	}
}

func productionKindName(k ProductionKind) string {
	switch k {
	case ProdTerminal:
		return "ProdTerminal"
	case ProdNonTerminal:
		return "ProdNonTerminal"
	case ProdAlternative:
		return "ProdAlternative"
	case ProdAlternation:
		return "ProdAlternation"
	case ProdOption:
		return "ProdOption"
	case ProdRepetition:
		return "ProdRepetition"
	case ProdRepetitionMandatory:
		return "ProdRepetitionMandatory"
	default:
		return fmt.Sprintf("ProductionKind(%d)", int(k))
	}
}
